mapper.select:
WITH latest_cycle AS ( SELECT x.party_id, x.billing_due_at FROM ( SELECT pc.party_id, pc.billing_due_at, ROW_NUMBER() OVER ( PARTITION BY pc.party_id ORDER BY pc.cycle_no DESC, pc.id DESC ) AS rn FROM party_cycle pc ) x WHERE x.rn = 1 ) SELECT p.id AS partyId, p.product_id AS productId, sp.service_name AS productName, sp.thumbnail_url AS thumbnailUrl, p.capacity AS totalCapacity, (p.current_member_count - COALESCE(rh.reserved_host_count, 0)) AS currentMemberCount, (p.capacity - (p.current_member_count - COALESCE(rh.reserved_host_count, 0))) AS remainingSeatCount, p.price_per_member_snapshot AS monthlyPaymentAmount, lc.billing_due_at AS nextPaymentDate, 'HOST_JOIN' AS joinButtonLabel FROM party p INNER JOIN sub_product sp ON sp.id = p.product_id LEFT JOIN latest_cycle lc ON lc.party_id = p.id LEFT JOIN ( SELECT pm.party_id, COUNT(*) AS reserved_host_count FROM party_member pm WHERE pm.role = 'HOST' AND pm.status = 'LEAVE_RESERVED' GROUP BY pm.party_id ) rh ON rh.party_id = p.id WHERE p.recruit_status = 'RECRUITING' AND p.vacancy_type = 'HOST' AND ( p.current_member_count < p.capacity OR COALESCE(rh.reserved_host_count, 0) > 0 )
AND p.product_id = #{productId}
ORDER BY CASE WHEN p.current_member_count < p.capacity THEN 0 ELSE 1 END ASC, lc.billing_due_at ASC, p.created_at ASC

WITH latest_cycle AS ( SELECT x.party_id, x.billing_due_at FROM ( SELECT pc.party_id, pc.billing_due_at, ROW_NUMBER() OVER ( PARTITION BY pc.party_id ORDER BY pc.cycle_no DESC, pc.id DESC ) AS rn FROM party_cycle pc ) x WHERE x.rn = 1 ) SELECT p.id AS partyId, p.product_id AS productId, sp.service_name AS productName, sp.thumbnail_url AS thumbnailUrl, p.capacity AS totalCapacity, (p.current_member_count - COALESCE(rm.reserved_member_count, 0)) AS currentMemberCount, (p.capacity - (p.current_member_count - COALESCE(rm.reserved_member_count, 0))) AS remainingSeatCount, p.price_per_member_snapshot AS monthlyPaymentAmount, lc.billing_due_at AS nextPaymentDate, '파티원 참여' AS joinButtonLabel, u.nickname AS hostNickname FROM party p INNER JOIN sub_product sp ON sp.id = p.product_id INNER JOIN users u ON u.id = p.host_user_id LEFT JOIN latest_cycle lc ON lc.party_id = p.id LEFT JOIN ( SELECT pm.party_id, COUNT(*) AS reserved_member_count FROM party_member pm WHERE pm.role = 'MEMBER' AND pm.status = 'LEAVE_RESERVED' GROUP BY pm.party_id ) rm ON rm.party_id = p.id WHERE p.recruit_status = 'RECRUITING' AND p.vacancy_type = 'MEMBER' AND ( p.current_member_count < p.capacity OR COALESCE(rm.reserved_member_count, 0) > 0 )
AND p.product_id = #{productId}
ORDER BY CASE WHEN p.current_member_count < p.capacity THEN 0 ELSE 1 END ASC, lc.billing_due_at ASC, p.created_at ASC
